import { useState } from 'react';
import { useAuthStore } from '../../store/useAuthStore';
import { toEmail, supabase } from '../../lib/supabase';
import './LoginPage.css';

/** 입력값을 이메일로 변환 — 한글이면 DB에서 display_name으로 조회 */
async function resolveEmail(input: string): Promise<string | null> {
  const trimmed = input.trim();
  if (!trimmed) return null;

  // 한글 이름이면 profiles에서 display_name으로 검색
  if (/[가-힣]/.test(trimmed)) {
    const { data } = await supabase
      .from('profiles')
      .select('email')
      .eq('display_name', trimmed)
      .single();
    if (data?.email) return data.email;
    return null; // 미등록
  }

  // 영문이면 그대로
  return toEmail(trimmed);
}

export default function LoginPage() {
  const { login, loading, error } = useAuthStore();
  const [userId, setUserId] = useState('');
  const [password, setPassword] = useState('');

  async function handleLogin(e: React.FormEvent) {
    e.preventDefault();
    if (!userId.trim() || !password) return;

    const email = await resolveEmail(userId);
    if (!email) {
      // 한글 이름인데 DB에 없음 → 미등록
      useAuthStore.setState({
        loading: false,
        error: '등록되지 않은 사용자입니다.\n임지현 010-3478-4253으로 권한을 요청하시기 바랍니다.',
      });
      return;
    }

    await login(email, password);

    // 로그인 실패 시 에러 메시지 커스텀
    const currentError = useAuthStore.getState().error;
    if (currentError === 'Invalid login credentials') {
      useAuthStore.setState({ error: '아이디 또는 비밀번호가 올바르지 않습니다.' });
    }
  }

  return (
    <div className="login-page">
      <form className="login-card" onSubmit={handleLogin}>
        <h1>주식회사 넥스트유니온<br/>스케쥴 관리 프로그램</h1>
        <p className="login-subtitle">로그인하여 스케줄을 확인하세요</p>

        {error && <div className="login-error" style={{ whiteSpace: 'pre-line' }}>{error}</div>}

        <div className="login-field">
          <label>아이디</label>
          <input
            type="text"
            value={userId}
            onChange={(e) => setUserId(e.target.value)}
            placeholder="관리자분의 성함을 써주세요 (예: 임지현)"
            autoComplete="username"
            autoFocus
          />
        </div>

        <div className="login-field">
          <label>비밀번호</label>
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="비밀번호 입력"
            autoComplete="current-password"
          />
        </div>

        <button className="login-btn" type="submit" disabled={loading}>
          {loading ? '로그인 중...' : '로그인'}
        </button>

        <p className="login-contact">
          문의 및 권한요청: 임지현 010-3478-4253
        </p>
      </form>
    </div>
  );
}
